export const meta = {
  name: 'verify-milne-substep2-bricks',
  description: 'Adversarially verify the landed Milne 3.3 sub-step 2 reconstruction bricks are sound + faithful (statements, not just kernel-clean)',
  phases: [
    { title: 'Verify', detail: 'three independent lenses on the landed lemmas' },
    { title: 'Synthesize', detail: 'merge verdicts' },
  ],
}

const ROOT = '/home/Axel/LeanAlgebraicGeometry-Horizon/MainProjects/Algebraic-Jacobian-Challenge'

const VERDICT = {
  type: 'object',
  additionalProperties: false,
  properties: {
    lens: { type: 'string' },
    sound: { type: 'boolean', description: 'true if no soundness/faithfulness defect found' },
    findings: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: {
          severity: { type: 'string', enum: ['blocker', 'major', 'minor', 'note'] },
          where: { type: 'string' },
          issue: { type: 'string' },
        },
        required: ['severity', 'where', 'issue'],
      },
    },
    summary: { type: 'string' },
  },
  required: ['lens', 'sound', 'findings', 'summary'],
}

const lenses = [
  {
    key: 'orientation-soundness',
    prompt: `You are auditing newly-added, kernel-verified Lean in ${ROOT}/AlgebraicJacobian/Albanese/DifferenceMap.lean. The declarations kernel-check and are axiom-clean, so DO NOT re-check compilation — hunt instead for a MIS-STATED lemma (a true-but-vacuous or orientation-reversed statement that formally passes but does not encode the intended math).

Milne, Abelian Varieties, Lemma 3.3: the difference map is Φ(x,y) = f(x)·f(y)⁻¹, and the reconstruction is f(x) = Φ(x,u)·f(u).

Scrutinize the GROUP ORIENTATION end-to-end:
1. CategoryTheory.GrpObj.diff (in this file, and its use) = fst/snd. In the T-points group Hom(G⊗G,G), is fst/snd really the map (g,h)↦g·h⁻¹? (i.e. is '/' left-division a·b⁻¹, matching Milne's f(x)f(y)⁻¹, not b⁻¹·a or a⁻¹·b?)
2. GrpObj.lift_diff_lift_mul proves 'lift (lift a b ≫ diff G) b ≫ μ = a'. Confirm lift a b ≫ diff = a/b (via GrpObj.comp_div), and lift (a/b) b ≫ μ = (a/b)*b (via Hom.mul_def: x*y = lift x y ≫ μ, so the FIRST lift-arg is the LEFT multiplicand). So this is (a·b⁻¹)·b = a. Is that Milne's reconstruction with a=f(x), b=f(u)? Would the statement still be true but WRONG if it were b*(a/b) instead (non-abelian)? Confirm the code uses (a/b)*b.
3. reconstruct_precomp_fst pairs 'prod ... (differenceRationalMap ...) (f.precomp pr₂ ...)' then '.compHom (grpObjMulLeft G)'. Confirm Φ is the FIRST prod-factor (→ fst → left multiplicand) and f∘pr₂ the SECOND, so the composite computes Φ·(f∘pr₂) = (a/b)·b = a = f∘pr₁, NOT (f∘pr₂)·Φ.
4. le_domain_precomp_fst_of_difference concludes 'Dom(Φ) ⊓ pr₂⁻¹(Dom f) ≤ Dom(f∘pr₁)'. Is the inequality DIRECTION correct and NON-vacuous (LHS not identically ⊥)? Does it actually advance Milne's converse (Φ defined at (x,x) ⟹ f defined at x), or is it a trivial restatement?

Read the file. Report any orientation flip, vacuity, or misstatement. Return the schema.`,
  },
  {
    key: 'hypothesis-hygiene',
    prompt: `You are auditing three newly-added, kernel-verified Lean files in ${ROOT}/AlgebraicJacobian/Albanese/: RationalMapPrecomp.lean (RationalMap.le_domain_precomp), RationalMapProd.lean (pairPartialMap, pairPartialMap_toRationalMap, le_domain_prod), DifferenceMap.lean (grpObjMulLeft, pullback_lift_diff_lift_mul, reconstruct_precomp_fst, le_domain_precomp_fst_of_difference). They kernel-check and are axiom-clean — do NOT re-check compilation.

Hunt for HIDDEN WEAKENING or unsatisfiable/over-strong hypotheses that make a lemma vacuous or unusable:
1. le_domain_prod requires [IsIntegral X][IsReduced X][Y.IsSeparated][Z.IsSeparated][S.IsSeparated][LocallyOfFiniteType sY][LocallyOfFiniteType sZ]. Are these all genuinely needed and jointly satisfiable in the Milne application (X = pullback X.hom X.hom, Y=Z=G.left, S=Spec k̄)? Any instance that could NEVER be synthesized (making the lemma dead)?
2. le_domain_precomp: is 'p ⁻¹ᵁ f.domain ≤ (f.precomp p hp).domain' the mathematically correct EASY inclusion (the hard reverse needs flat descent)? Confirm it is NOT accidentally the reverse (which would be false / need descent).
3. pairPartialMap: it pairs a.toPartialMap and b.toPartialMap. Does the over-S compatibility proof (ea/eb from PartialMap.isOver_iff) actually hold, or could it be exploiting a defeq that silently changes the map? Check that the domain is a.domain⊓b.domain (dense) and that pairPartialMap_toRationalMap genuinely proves it REPRESENTS prod (matches BOTH pullback legs).
4. Cross-check: le_domain_precomp_fst_of_difference chains reconstruct + le_domain_compHom + le_domain_prod + le_domain_precomp. Is the chain logically valid (each ⊆ in the right direction), or does some step go the wrong way and only typecheck by luck?

Read the files. Report any vacuity, wrong-direction inclusion, or unsatisfiable hypothesis. Return the schema.`,
  },
  {
    key: 'blueprint-correspondence',
    prompt: `You are auditing the blueprint edits in ${ROOT}/blueprint/src/chapters/Albanese_CodimOneExtension.tex (6 new nodes added after lem:difference_map_domain_lower_bound: lem:rationalMap_precomp_domain_bound, lem:rationalMap_prod_domain_bound, lem:grpObj_reconstruction, lem:scheme_reconstruction, lem:rationalMap_difference_reconstruct, lem:difference_map_domain_reconstruction) against the Lean in ${ROOT}/AlgebraicJacobian/Albanese/{RationalMapPrecomp,RationalMapProd,DifferenceMap}.lean.

Check, for EACH of the 6 new nodes:
1. Does the \\lean{...} pin name an actual declaration in the Lean files, and does the LaTeX STATEMENT faithfully match that declaration's Lean statement (same hypotheses, same conclusion, same direction)? Flag any node whose prose claims more/less than the Lean.
2. Is the \\begin{proof}...\\end{proof} a COMPLETE argument (house style requires complete, not sketched, proofs) and marked \\leanok consistently with the file being kernel-clean?
3. MATH-PURITY: the prose must be pure mathematics — flag any Lean identifiers/tactic names leaking into statements or proofs (\\lean{} and \\cref{} are fine; bare Lean names in prose are not).
4. \\uses wiring: are the \\uses lists sensible (referencing existing labels), and is the main lemma lem:milne_codim1_indeterminacy's \\uses updated to include lem:rationalMap_difference_reconstruct and lem:difference_map_domain_reconstruction?

Also sanity-check the substep-2 prose edit near 'algebraic content is now formal'. Read both the tex and the Lean. Report mismatches. Return the schema.`,
  },
]

phase('Verify')
const results = await parallel(lenses.map(l => () =>
  agent(l.prompt, { label: `verify:${l.key}`, phase: 'Verify', schema: VERDICT })
))

phase('Synthesize')
const valid = results.filter(Boolean)
const allFindings = valid.flatMap(v => (v.findings || []).map(f => ({ ...f, lens: v.lens })))
const blockers = allFindings.filter(f => f.severity === 'blocker' || f.severity === 'major')
return {
  lensesRun: valid.length,
  allSound: valid.every(v => v.sound),
  blockersAndMajors: blockers,
  allFindings,
  perLensSummary: valid.map(v => ({ lens: v.lens, sound: v.sound, summary: v.summary })),
}
